
import DataTable from '@/components/DataTable'
import React from 'react'
import Image from "next/image";
import Link from 'next/link';
import { TrendingDown, TrendingUp } from 'lucide-react';
import { cn } from '@/lib/utils';
import { fetcher } from '@/lib/coingecko.action';

const coinNames = [
  'Bitcoin', 'Ethereum', 'Solana', 'Cardano', 'XRP',
  'Polkadot', 'Litecoin', 'Chainlink', 'Dogecoin', 'Avalanche'
];

export const trendingCoins: TrendingCoin[] = Array.from({ length: 50 }, (_, i) => {
  const name = coinNames[i % coinNames.length];
  const price = (Math.random() * 50000 + 1000).toFixed(2);
  const change = (Math.random() * 10 - 5).toFixed(2); // -5% to +5%

  return {
    item: {
      id: `${name.toLowerCase()}-${i}`,
      name: name,
      large: `/coins/${name.toLowerCase()}.png`, // make sure images exist
      data: {
        price: `$${price}`,
        price_change_percentage_24h: {
          usd: Number(change),
        },
      },
    },
  };
});

const columns: DataTableColumn<TrendingCoin>[] = [
  {
    header: 'Name',
    cell: (coin) => {
      const item = coin.item;
      return (
        <Link href={`/coins/${item.id}`} className="flex items-center gap-2">
          <Image src={item.large} alt={item.name} width={36} height={36} />
          <p>{item.name}</p>
        </Link>
      );
    },
  },
  {
    header: "24h Change",
    cell: (coin) => {
      const item = coin.item;
      const isUp = item.data.price_change_percentage_24h.usd > 0;

      return (
        <div className={cn(
          'flex items-center gap-1',
          isUp ? 'text-green-500' : 'text-red-500'
        )}>
          {isUp ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
          <span>{item.data.price_change_percentage_24h.usd}%</span>
        </div>
      );
    },
  },
  {
    header: "Price",
    cell: (coin) => coin.item.data.price,
  },
];
const Page = async  () => {
  const coin = await fetcher<CoinDetailsData>('/coins/bitcoin', {
    dex_pair_format: 'symbol'
  })
  return (
    <main className='main-container'>
      <section className='home-grid'>

        <div id='coin-overview'>
          <div className='header pt-2 flex items-center gap-3'>
            <Image src={coin.image.large} alt={coin.name} width={56} height={56} />
            <div className='info'>
              <p>{coin.name}</p>
              <h1>{coin.market_data.current_price.usd}</h1>
            </div>
          </div>
        </div>

       
        <p>Trending Coins</p>

        <DataTable
          data={trendingCoins}
          columns={columns}
          rowKey={(row) => row.item.id}
        />

      </section>

      <section className='w-full mt-7 space-y-4'>
        <p>Categories</p>
      </section>
    </main>
  );
};

export default Page;


